\begin{proof}
    Denote $l_1 = \mathcal{L}(x)$ and $l_2 = \mathcal{L}(y)$.
    Since $c(\overline{\partial}_{[l_1]}(y)) \subseteq [n] \setminus [l_1]$, Lemma~\ref{lemma:shorten}~(\ref{lemma:shorten:i}) implies
    \begin{align*}
        \overline{\partial}_{[l_1]}(x y) &= \overline{\partial}_{[l_1]}(x) \overline{\partial}_{[l_1]}(y) \\
        &= e_{[n] \setminus [l_1]} \overline{\partial}_{[l_1]}(y) \\
        &= e_{[n] \setminus [l_1]},
    \end{align*}
    which proves $\mathcal{L}(x y) \leq l_1$.
    Since $c(\overline{\partial}_{[l_2]}(x)) \subseteq [n] \setminus [l_2]$, Lemma~\ref{lemma:shorten}~(\ref{lemma:shorten:ii}) implies
    \begin{align*}
        \overline{\partial}_{[l_2]}(x y) &= \overline{\partial}_{[l_2]}(x) \overline{\partial}_{[l_2]}(y) \\
        &= \overline{\partial}_{[l_2]}(x) e_{[n] \setminus [l_2]} \\
        &= e_{[n] \setminus [l_2]},
    \end{align*}
    which proves $\mathcal{L}(x y) \leq l_2$.
    This concludes the proof.
\end{proof}

